UPDATE dp_widget_lib /* base.ec.dp :: DpWidgetLib :: updateSelective */
site_id = #{siteId}, widget_code = #{widgetCode}, widget_nm = #{widgetNm}, widget_type_cd = #{widgetTypeCd}, widget_lib_desc = #{widgetLibDesc}, path_id = #{pathId}, thumbnail_url = #{thumbnailUrl}, template_html = #{templateHtml}, config_schema = #{configSchema}, is_system = #{isSystem}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE widget_lib_id = #{widgetLibId}
